<style>
/* 容器布局 */
.glass-container {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(500px, 1fr));
  gap: 30px; /* 稍微增大间距，给阴影留出空间 */
  margin-top: 20px;
  padding: 10px; /* 容器加点内边距，防止阴影被裁切 */
}

/* 液态玻璃卡片容器 */
.glass-card {
  position: relative;
  border-radius: 16px;
  overflow: hidden;
  background: rgba(255, 255, 255, 0.03); /* 降低背景透明度，增强玻璃感 */
  backdrop-filter: blur(15px); /* 增加模糊度 */
  -webkit-backdrop-filter: blur(15px);
  border: 1px solid rgba(255, 255, 255, 0.08); /* 极细的玻璃边缘 */
  transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275), box-shadow 0.4s ease; /* 增加阴影过渡 */

  /* ✨ 新增：基础阴影 (淡雅、柔和) */
  box-shadow: 0 10px 30px -10px rgba(0, 0, 0, 0.15); 
}

/* 适配 Butterfly 暗黑模式的基础阴影 */
[data-theme="dark"] .glass-card {
  box-shadow: 0 10px 40px -15px rgba(0, 0, 0, 0.5);
}

/* ✨ 新增：悬浮效果 (浮起 + 霓虹阴影) */
.glass-card:hover {
  transform: translateY(-12px) scale(1.02); /* 向上浮起更多，并轻微放大 */

  /* 悬浮时的强力阴影，带有淡淡的霓虹蓝晕 */
  box-shadow: 0 25px 60px -15px rgba(73, 177, 245, 0.25); 
}

/* 核心流光背景层 */
.glass-border-anim {
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: conic-gradient(
    transparent,
    rgba(0, 242, 254, 0.6), /* 霓虹蓝 */
    transparent 30%
  );
  animation: rotateFluid 4s linear infinite;
  z-index: 1;
  opacity: 0;
  transition: opacity 0.3s;
}

.glass-card:hover .glass-border-anim {
  opacity: 1;
}

/* 内容遮罩层 */
.glass-content {
  position: relative;
  z-index: 2;
  margin: 2px; /* 露出的空隙就是流光边框 */
  background: var(--card-bg); /* 适配 Butterfly 主题背景 */
  border-radius: 14px;
  padding: 25px;
  height: calc(100% - 4px);
  display: flex;
  flex-direction: column;
}

/* 适配 Butterfly 暗黑模式的透明度 */
[data-theme="dark"] .glass-content {
  background: rgba(18, 18, 18, 0.8) !important; /* 降低暗色模式下的背景不透明度 */
}

/* 内部元素样式 (保持不变) */
.project-badge {
  align-self: flex-end;
  background: linear-gradient(135deg, #00f2fe 0%, #4facfe 100%);
  color: #fff;
  padding: 2px 10px;
  border-radius: 10px;
  font-size: 11px;
  font-weight: bold;
  box-shadow: 0 2px 8px rgba(79, 172, 254, 0.3); /* 标签加点小阴影 */
}

.project-icon {
  font-size: 2.5rem; /* 增大图标 */
  color: #49b1f5;
  margin: 10px 0;
  opacity: 0.9;
}

.project-title {
  margin: 10px 0 !important;
  font-size: 1.4rem !important; /* 增大标题 */
  color: var(--text-highlight-color) !important;
  font-weight: bold !important;
}

.project-desc {
  font-size: 0.92rem;
  line-height: 1.8; /* 增大行高，增加可读性 */
  color: var(--font-color);
  opacity: 0.8;
  margin-bottom: 20px;
  flex-grow: 1;
}

.project-tech {
  display: flex;
  flex-wrap: wrap;
  gap: 8px; /* 增大间距 */
  margin-bottom: 25px;
}

.project-tech span {
  background: rgba(128, 128, 128, 0.1);
  padding: 3px 10px; /* 增大内边距 */
  border-radius: 6px;
  font-size: 11px;
  border: 1px solid rgba(128, 128, 128, 0.1);
  font-family: monospace; /* 程序员字体 */
}

.project-link {
  color: #49b1f5 !important;
  font-weight: bold;
  text-decoration: none !important;
  font-size: 1rem;
  transition: all 0.3s;
}

.project-link i {
  transition: transform 0.3s;
}

.project-link:hover {
  letter-spacing: 1px; /* 悬浮时文字略微展开 */
}

.project-link:hover i {
  transform: translateX(5px); /* 箭头滑动 */
}

/* 旋转动画 */
@keyframes rotateFluid {
  100% { transform: rotate(1turn); }
}
</style>
